494: // watch starts a watch request with the server, consumes watch events, and
495: // restarts the watch until an exit scenario is reached.
496: //
497: // If a watch is provided, it will be used, otherwise another will be started.
498: // If the watcher has started, it will always be stopped before returning.
499: func (r *Reflector) watch(ctx context.Context, w watch.Interface, resyncerrc chan error) error {
500: 	stopCh := ctx.Done()
501: 	logger := klog.FromContext(ctx)
502: 	var err error
503: 	retry := NewRetryWithDeadline(r.MaxInternalErrorRetryDuration, time.Minute, apierrors.IsInternalError, r.clock)
504: 	defer func() {
505: 		if w != nil {
506: 			w.Stop()
507: 		}
508: 	}()
509: 
510: 	for {
511: 		// give the stopCh a chance to stop the loop, even in case of continue statements further down on errors
512: 		select {
513: 		case <-stopCh:
514: 			// we can only end up here when the stopCh
515: 			// was closed after a successful watchlist or list request
516: 			return nil
517: 		default:
518: 		}
519: 
520: 		// start the clock before sending the request, since some proxies won't flush headers until after the first watch event is sent
521: 		start := r.clock.Now()
522: 
523: 		if w == nil {
524: 			timeoutSeconds := int64(r.minWatchTimeout.Seconds() * (rand.Float64() + 1.0))
525: 			options := metav1.ListOptions{
526: 				ResourceVersion: r.LastSyncResourceVersion(),
527: 				// We want to avoid situations of hanging watchers. Stop any watchers that do not
528: 				// receive any events within the timeout window.
529: 				TimeoutSeconds: &timeoutSeconds,
530: 				// To reduce load on kube-apiserver on watch restarts, you may enable watch bookmarks.
531: 				// Reflector doesn't assume bookmarks are returned at all (if the server do not support
532: 				// watch bookmarks, it will ignore this field).
533: 				AllowWatchBookmarks: true,
534: 			}
535: 
536: 			w, err = r.listerWatcher.WatchWithContext(ctx, options)
537: 			if err != nil {
538: 				if canRetry := isWatchErrorRetriable(err); canRetry {
539: 					logger.V(4).Info("Watch failed - backing off", "reflector", r.name, "type", r.typeDescription, "err", err)
