541: 					case <-stopCh:
542: 						return nil
543: 					case <-r.backoffManager.Backoff().C():
544: 						continue
545: 					}
546: 				}
547: 				return err
548: 			}
549: 		}
550: 
551: 		err = handleWatch(ctx, start, w, r.store, r.expectedType, r.expectedGVK, r.name, r.typeDescription, r.setLastSyncResourceVersion,
552: 			r.clock, resyncerrc)
553: 		// handleWatch always stops the watcher. So we don't need to here.
554: 		// Just set it to nil to trigger a retry on the next loop.
555: 		w = nil
556: 		retry.After(err)
557: 		if err != nil {
558: 			if !errors.Is(err, errorStopRequested) {
559: 				switch {
560: 				case isExpiredError(err):
561: 					// Don't set LastSyncResourceVersionUnavailable - LIST call with ResourceVersion=RV already
562: 					// has a semantic that it returns data at least as fresh as provided RV.
563: 					// So first try to LIST with setting RV to resource version of last observed object.
564: 					logger.V(4).Info("Watch closed", "reflector", r.name, "type", r.typeDescription, "err", err)
565: 				case apierrors.IsTooManyRequests(err):
566: 					logger.V(2).Info("Watch returned 429 - backing off", "reflector", r.name, "type", r.typeDescription)
567: 					select {
568: 					case <-stopCh:
569: 						return nil
570: 					case <-r.backoffManager.Backoff().C():
571: 						continue
572: 					}
573: 				case apierrors.IsInternalError(err) && retry.ShouldRetry():
574: 					logger.V(2).Info("Retrying watch after internal error", "reflector", r.name, "type", r.typeDescription, "err", err)
575: 					continue
576: 				default:
577: 					logger.Info("Warning: watch ended with error", "reflector", r.name, "type", r.typeDescription, "err", err)
578: 				}
579: 			}
580: 			return nil
581: 		}
582: 	}
583: }
