662: 	}
663: 
664: 	logger := ptr.Deref(options.Logger, klog.Background())
665: 	resyncPeriod := ptr.Deref(options.ResyncPeriod, s.defaultEventHandlerResyncPeriod)
666: 	if resyncPeriod > 0 {
667: 		if resyncPeriod < minimumResyncPeriod {
668: 			logger.Info("Warning: resync period is too small. Changing it to the minimum allowed value", "resyncPeriod", resyncPeriod, "minimumResyncPeriod", minimumResyncPeriod)
669: 			resyncPeriod = minimumResyncPeriod
670: 		}
671: 
672: 		if resyncPeriod < s.resyncCheckPeriod {
673: 			if s.started {
674: 				logger.Info("Warning: resync period is smaller than resync check period and the informer has already started. Changing it to the resync check period", "resyncPeriod", resyncPeriod, "resyncCheckPeriod", s.resyncCheckPeriod)
