676: 				resyncPeriod = s.resyncCheckPeriod
677: 			} else {
678: 				// if the event handler's resyncPeriod is smaller than the current resyncCheckPeriod, update
679: 				// resyncCheckPeriod to match resyncPeriod and adjust the resync periods of all the listeners
680: 				// accordingly
